-	if leftIDs, err := sm.buildIDSet(leftPath); err == nil && len(leftIDs) > 0 {
-		protectedIDs = leftIDs
-	}
-
-	// Read current JSONL
-	f, err := os.Open(jsonlPath) // #nosec G304 - controlled path
-	if err != nil {
-		if os.IsNotExist(err) {
-			return result, nil // No JSONL file yet
