-	var keptLines [][]byte
-
-	scanner := bufio.NewScanner(f)
-	// Allow large lines (up to 10MB for issues with large descriptions)
-	scanner.Buffer(make([]byte, 0, 64*1024), 10*1024*1024)
-
-	for scanner.Scan() {
-		line := scanner.Bytes()
