-	_ = f.Close()
-
-	// If nothing was removed, we're done
-	if result.RemovedCount == 0 {
-		return result, nil
-	}
-
-	// Write sanitized JSONL atomically
-	dir := filepath.Dir(jsonlPath)
-	base := filepath.Base(jsonlPath)
